import{_ as r,c as t,o as s,ah as e}from"./chunks/framework.DwHsq7Fg.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/safety-measures.md","filePath":"basics_api/safety-measures.md"}'),n={name:"basics_api/safety-measures.md"};function i(l,o,a,g,c,p){return s(),t("div",null,o[0]||(o[0]=[e('<h3 id="б-заходи-безпеки-захист-вашого-api" tabindex="-1">Б) Заходи безпеки: Захист вашого API <a class="header-anchor" href="#б-заходи-безпеки-захист-вашого-api" aria-label="Permalink to “Б) Заходи безпеки: Захист вашого API”">​</a></h3><p>Після того, як ви автентифікували користувачів або програми, важливо вжити заходів для захисту вашого API від зловмисного використання, несанкціонованого доступу та інших загроз. Ось деякі ключові заходи безпеки:</p><h4 id="🚦-→-rate-limiting-обмеження-швидкості" tabindex="-1">🚦 → Rate Limiting (Обмеження швидкості) <a class="header-anchor" href="#🚦-→-rate-limiting-обмеження-швидкості" aria-label="Permalink to “🚦 → Rate Limiting (Обмеження швидкості)”">​</a></h4><p><strong>Що це?</strong></p><p>Rate Limiting (обмеження швидкості) - це механізм, який <strong>обмежує кількість запитів</strong>, які клієнт може зробити до API протягом певного періоду часу. Це як встановлення <strong>лічильника</strong> ⏱️ для кожного користувача або IP-адреси, щоб запобігти зловживанню.</p><p><strong>Як це працює?</strong></p><p>Сервер API відстежує кількість запитів від кожного клієнта (ідентифікованого за IP-адресою, API-ключем, токеном тощо) протягом певного часового вікна (наприклад, 100 запитів за хвилину).</p><p>Якщо клієнт перевищує встановлений ліміт, сервер тимчасово блокує подальші запити від цього клієнта та повертає помилку (зазвичай <code>429 Too Many Requests</code>).</p><p><strong>Переваги:</strong></p><ul><li><strong>Захист від DoS/DDoS атак:</strong> Допомагає запобігти атакам типу &quot;відмова в обслуговуванні&quot; (Denial of Service) або розподіленим атакам (Distributed Denial of Service), коли зловмисники намагаються перевантажити API великою кількістю запитів.</li><li><strong>Запобігання зловживанню:</strong> Обмежує можливість окремих користувачів або програм надмірно використовувати ресурси API.</li><li><strong>Справедливе використання:</strong> Забезпечує рівномірний доступ до API для всіх клієнтів.</li><li><strong>Контроль витрат:</strong> Допомагає контролювати витрати на інфраструктуру, пов&#39;язані з використанням API.</li></ul><p><strong>Реалізація:</strong></p><p>Обмеження швидкості може бути реалізовано на різних рівнях:</p><ul><li><strong>На рівні веб-сервера:</strong> Модулі веб-серверів (наприклад, <code>mod_ratelimit</code> для Apache, <code>ngx_http_limit_req_module</code> для Nginx).</li><li><strong>На рівні API Gateway:</strong> Шлюзи API часто мають вбудовані функції обмеження швидкості.</li><li><strong>На рівні коду застосунку:</strong> За допомогою спеціальних бібліотек або власної логіки.</li></ul><p><strong>Приклад:</strong></p><p>&quot;Цей API дозволяє робити не більше 100 запитів на хвилину з однієї IP-адреси.&quot;</p><hr><h4 id="🌐-→-cors-cross-origin-resource-sharing" tabindex="-1">🌐 → CORS (Cross-Origin Resource Sharing) <a class="header-anchor" href="#🌐-→-cors-cross-origin-resource-sharing" aria-label="Permalink to “🌐 → CORS (Cross-Origin Resource Sharing)”">​</a></h4><p><strong>Що це?</strong></p><p>CORS (Cross-Origin Resource Sharing) - це <strong>механізм безпеки браузера</strong>, який <strong>контролює, чи дозволено веб-сторінці, що завантажена з одного домену (origin), робити запити до ресурсів (наприклад, API) на іншому домені</strong>. Уявіть собі, як браузер виступає <strong>прикордонником</strong> 🛂, який перевіряє, чи має веб-сайт право &quot;перетинати кордон&quot; і отримувати дані з іншого сайту.</p><p><strong>Проблема &quot;Same-Origin Policy&quot;:</strong></p><p>За замовчуванням браузери застосовують політику &quot;Same-Origin Policy&quot;, яка забороняє JavaScript-коду на одній сторінці робити запити до іншого домену з міркувань безпеки (щоб запобігти, наприклад, викраденню даних).</p><p><strong>Як CORS вирішує проблему:</strong></p><p>CORS дозволяє серверу API явно вказати, <strong>які саме інші домени (origins)</strong> мають право робити до нього запити. Це робиться за допомогою спеціальних <strong>HTTP-заголовків</strong> у відповіді сервера.</p><p><strong>Основні CORS-заголовки:</strong></p><ul><li><strong><code>Access-Control-Allow-Origin</code>:</strong> Вказує, яким доменам дозволено доступ до ресурсу. Значенням може бути конкретний домен (наприклад, <code>https://example.com</code>) або <code>*</code> (дозволити доступ з будь-якого домену - використовувати з обережністю!).</li><li><strong><code>Access-Control-Allow-Methods</code>:</strong> Вказує, які HTTP-методи (GET, POST, PUT, DELETE тощо) дозволені для крос-доменних запитів.</li><li><strong><code>Access-Control-Allow-Headers</code>:</strong> Вказує, які нестандартні HTTP-заголовки дозволено використовувати у крос-доменних запитах.</li><li><strong><code>Access-Control-Allow-Credentials</code>:</strong> Вказує, чи можуть крос-доменні запити включати куки та заголовки авторизації.</li></ul><p><strong>Як це працює (спрощено):</strong></p><ol><li>Браузер клієнта робить крос-доменний запит до API.</li><li>Браузер може спочатку відправити так званий &quot;preflight request&quot; (попередній запит) методом <code>OPTIONS</code> з CORS-заголовками, щоб дізнатися про дозволи сервера.</li><li>Сервер API відповідає на preflight request заголовками <code>Access-Control-Allow-Origin</code>, <code>Access-Control-Allow-Methods</code>, <code>Access-Control-Allow-Headers</code> тощо, вказуючи свої CORS-політики.</li><li>Якщо політики сервера дозволяють запит клієнта (домен, метод, заголовки), браузер відправляє фактичний запит.</li><li>Сервер API відповідає на фактичний запит, також включаючи CORS-заголовки.</li><li>Браузер перевіряє CORS-заголовки у відповіді. Якщо вони відповідають політиці безпеки браузера, браузер дозволяє JavaScript-коду отримати доступ до відповіді. Інакше - блокує доступ.</li></ol><p><strong>Важливість:</strong></p><p>CORS є важливим механізмом безпеки, який дозволяє контролювати, які веб-сайти можуть взаємодіяти з вашим API, запобігаючи потенційним атакам міжсайтового скриптингу (XSS) та іншим загрозам.</p><hr><h4 id="🔒-→-https-tls-http-secure-transport-layer-security" tabindex="-1">🔒 → HTTPS/TLS (HTTP Secure/Transport Layer Security) <a class="header-anchor" href="#🔒-→-https-tls-http-secure-transport-layer-security" aria-label="Permalink to “🔒 → HTTPS/TLS (HTTP Secure/Transport Layer Security)”">​</a></h4><p><strong>Що це?</strong></p><p>HTTPS (HTTP Secure) - це <strong>безпечна версія протоколу HTTP</strong>, яка використовує <strong>шифрування TLS/SSL (Transport Layer Security/Secure Sockets Layer)</strong> для захисту передачі даних між клієнтом (наприклад, браузером) та сервером API. Уявіть собі, як ваші інтернет-дані подорожують через <strong>зашифрований тунель</strong> tunnel 🛡️, який ніхто не може підглянути.</p><p><strong>Як це працює:</strong></p><ol><li><strong>TLS/SSL Handshake (Рукостискання):</strong> Коли клієнт намагається підключитися до HTTPS-сайту або API, відбувається процес &quot;рукостискання&quot;. Клієнт і сервер обмінюються інформацією для встановлення безпечного з&#39;єднання, включаючи вибір криптографічних алгоритмів та обмін сертифікатами.</li><li><strong>Сертифікат SSL/TLS:</strong> Сервер надає клієнту свій сертифікат SSL/TLS. Цей сертифікат містить інформацію про ідентичність сервера та його публічний ключ. Він підписується довіреним центром сертифікації (CA), що підтверджує легітимність сервера.</li><li><strong>Шифрування:</strong> Після успішного рукостискання клієнт і сервер використовують узгоджені криптографічні алгоритми та ключі для шифрування всіх даних, що передаються між ними. Це означає, що навіть якщо хтось перехопить трафік, він побачить лише зашифровані дані, які буде складно розшифрувати без відповідних ключів.</li></ol><p><strong>Переваги:</strong></p><ul><li><strong>Конфіденційність:</strong> Запобігає перехопленню та прочитанню даних третіми особами (наприклад, хакерами, інтернет-провайдерами).</li><li><strong>Цілісність:</strong> Гарантує, що дані не були змінені під час передачі.</li><li><strong>Автентичність:</strong> Сертифікат SSL/TLS допомагає клієнту переконатися, що він спілкується з легітимним сервером, а не з підробленим сайтом (хоча це більше стосується перевірки домену).</li></ul><p><strong>Важливість для API:</strong></p><p>Використання HTTPS/TLS є <strong>абсолютно необхідним</strong> для будь-якого API, який обробляє конфіденційні дані (наприклад, облікові дані користувачів, платіжну інформацію) або будь-яку іншу інформацію, яку не слід передавати у відкритому вигляді.</p><p><strong>Реалізація:</strong></p><p>Для впровадження HTTPS/TLS потрібно:</p><ul><li>Отримати сертифікат SSL/TLS для вашого домену.</li><li>Налаштувати ваш веб-сервер (наприклад, Apache, Nginx) для використання цього сертифіката та протоколу HTTPS.</li><li>Переконатися, що всі клієнтські запити до API надсилаються через протокол <code>https://</code>.</li></ul><hr><p>Застосування цих заходів безпеки є критично важливим для забезпечення надійності, конфіденційності та захисту вашого API та його користувачів.</p>',44)]))}const u=r(n,[["render",i]]);export{d as __pageData,u as default};
